1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
14	
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_YEARS_THRESHOLD = 2;
20	
21	type Scenario = {
22	  customer: { yearsWithMHPCO: number };
23	  steps: Array<{ op: "quote"; items: Item[] }>;
24	};
25	
26	type QuoteResult = { premium: number };
27	
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	
31	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
32	
33	const sumOfBasePremiums = (items: Item[]): number =>
34	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
35	
36	const groupByType = (items: Item[]): Item[][] => {
37	  const groups = items.reduce<Record<string, Item[]>>((acc, item) => {
38	    (acc[item.type] ??= []).push(item);
39	    return acc;
40	  }, {});
41	  return Object.values(groups);
42	};
43	
44	const basePremiumForGroup = (group: Item[]): number =>
45	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
46	
47	const basePremiumFor = (items: Item[]): number =>
48	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
49	
50	type SurchargeRule = { rate: number; applies: (item: Item) => boolean };
51	
52	const SURCHARGE_RULES: SurchargeRule[] = [
53	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
54	  {
55	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
56	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
57	  },
58	];
59	
60	const surchargeForRule = (items: Item[], rule: SurchargeRule): number =>
61	  items.reduce(
62	    (sum, item) => (rule.applies(item) ? sum + BASE_PREMIUMS[item.type] * rule.rate : sum),
63	    0,
64	  );
65	
66	const surchargesFor = (items: Item[]): number =>
67	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
68	
69	type Customer = { yearsWithMHPCO: number };
70	
71	const loyaltyDiscountFor = (base: number, customer: Customer): number =>
72	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? base * LOYALTY_DISCOUNT_RATE : 0;
73	
74	const quotePremium = (items: Item[], customer: Customer): QuoteResult => {
75	  const base = basePremiumFor(items);
76	  const surcharges = surchargesFor(items);
77	  const loyalty = loyaltyDiscountFor(base, customer);
78	  return {
79	    premium: Math.ceil(
80	      base + surcharges - loyalty + base * FIRST_INSURANCE_RATE + PROCESSING_FEE,
81	    ),
82	  };
83	};
84	
85	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
86	  const results = scenario.steps.map((step) => quotePremium(step.items, scenario.customer));
87	  return { results };
88	};
